function solve(n, edges) {
  const adj = Array.from({ length: n }, () => []);
  for (const [from, to] of edges) {
    adj[from].push(to);
  }

  const UNVISITED = 0, VISITING = 1, VISITED = 2;
  const state = new Array(n).fill(UNVISITED);

  function hasCycle(node) {
    state[node] = VISITING;
    for (const neighbor of adj[node]) {
      if (state[neighbor] === VISITING) return true;
      if (state[neighbor] === UNVISITED && hasCycle(neighbor)) return true;
    }
    state[node] = VISITED;
    return false;
  }

  for (let i = 0; i < n; i++) {
    if (state[i] === UNVISITED && hasCycle(i)) return true;
  }

  return false;
}

